css:
.loader {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      gap: 4px;
      height: 36px;
    }
    .loader i {
      display: block;
      width: 6px;
      height: 36px;
      border-radius: 999px;
      background: linear-gradient(180deg, var(--loader-color), var(--loader-secondary-color));
      transform-origin: center bottom;
      animation: barPulse 1.05s ease-in-out infinite;
    }
    .loader i:nth-child(1) { animation-delay: 0.00s; }
.loader i:nth-child(2) { animation-delay: 0.09s; }
.loader i:nth-child(3) { animation-delay: 0.18s; }
.loader i:nth-child(4) { animation-delay: 0.27s; }
.loader i:nth-child(5) { animation-delay: 0.36s; }
    @keyframes barPulse { 0%, 100% { transform: scaleY(.42); opacity: .45; } 50% { transform: scaleY(1); opacity: 1; } }
